import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { normalizeTags } from './normalizeTags';

describe('normalizeTags', () => {
  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('should handle happy path: normal tags without duplicates or spaces', () => {
    const input = ['JavaScript', 'Testing', 'Vitest'];
    const result = normalizeTags(input);
    expect(result).toEqual(['javascript', 'testing', 'vitest']);
  });

  it('should handle edge case: tags with mixed cases, spaces, and duplicates', () => {
    const input = ['  Node.js  ', 'node.js', 'API', 'api ', '   '];
    const result = normalizeTags(input);
    expect(result).toEqual(['node.js', 'api']);
  });

  it('should handle null/empty: null, undefined, empty string, 0', () => {
    expect(normalizeTags(null as any)).toEqual([]);
    expect(normalizeTags(undefined as any)).toEqual([]);
    expect(normalizeTags(['', '   ', 0] as any)).toEqual([]);
    expect(normalizeTags([])).toEqual([]);
  });
});

