import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Assume the function is exported from './notesUtils'
import { sortNotesByUpdatedAt } from './notesUtils';

describe('sortNotesByUpdatedAt', () => {
  // Happy path test - notes with different timestamps
  it('should handle happy path: return notes sorted by updatedAt descending', () => {
    const notes = [
      { id: 1, title: 'A', updatedAt: new Date('2023-01-01') },
      { id: 2, title: 'B', updatedAt: new Date('2023-03-01') },
      { id: 3, title: 'C', updatedAt: new Date('2023-02-01') },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    expect(sorted).toEqual([
      { id: 2, title: 'B', updatedAt: new Date('2023-03-01') },
      { id: 3, title: 'C', updatedAt: new Date('2023-02-01') },
      { id: 1, title: 'A', updatedAt: new Date('2023-01-01') },
    ]);
  });

  // Edge case test - notes with identical timestamps
  it('should handle edge case: notes with equal updatedAt keep original order', () => {
    const equalTime = new Date('2023-05-01');
    const notes = [
      { id: 1, title: 'X', updatedAt: equalTime },
      { id: 2, title: 'Y', updatedAt: equalTime },
      { id: 3, title: 'Z', updatedAt: equalTime },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    // Should preserve original order when timestamps are equal
    expect(sorted).toEqual(notes);
  });

  // Null/empty test - handling null, undefined, empty array and falsy values
  it('should handle null/empty inputs gracefully', () => {
    expect(sortNotesByUpdatedAt(null)).toEqual([]);
    expect(sortNotesByUpdatedAt(undefined)).toEqual([]);
    expect(sortNotesByUpdatedAt([])).toEqual([]);

    // If a note missing updatedAt is passed, it should be treated as minimal date
    const notes = [
      { id: 1, title: 'No date' },
      { id: 2, title: 'With date', updatedAt: new Date('2023-04-01') },
    ];
    const sorted = sortNotesByUpdatedAt(notes);
    expect(sorted).toEqual([
      { id: 2, title: 'With date', updatedAt: new Date('2023-04-01') },
      { id: 1, title: 'No date' },
    ]);
  });
});

